    public static function rest_register(WP_REST_Request $request) {
        $username = (string)$request->get_param('username');
        $email = (string)$request->get_param('email');
        $password = (string)$request->get_param('password');

        $result = self::register_user($username, $email, $password);
        if (is_wp_error($result)) {
            return new WP_REST_Response(['ok' => false, 'error' => $result->get_error_message()], 400);
        }

        $auth = self::authenticate($username, $password);
        if (!is_wp_error($auth)) {
            self::set_logged_in_user($auth);
        }

        return new WP_REST_Response(['ok' => true, 'user_id' => (int)$result], 201);
    }

    public static function rest_login(WP_REST_Request $request) {
        $identifier = (string)$request->get_param('identifier');
        $password = (string)$request->get_param('password');

        $auth = self::authenticate($identifier, $password);
        if (is_wp_error($auth)) {
            return new WP_REST_Response(['ok' => false, 'error' => $auth->get_error_message()], 401);
        }

        self::set_logged_in_user($auth);

        return new WP_REST_Response(['ok' => true, 'user' => $auth], 200);
    }

    public static function rest_me(WP_REST_Request $request) {
        $u = self::current_user();
        if (!$u) {
            return new WP_REST_Response(['ok' => false, 'error' => 'Not logged in.'], 401);
        }
        return new WP_REST_Response(['ok' => true, 'user' => $u], 200);
    }

    public static function rest_logout(WP_REST_Request $request) {
